const input = $json;

// 🔹 dados_sadm (TUDO)
const dados_sadm = input.input_original;

// 🔹 consolidado inicial
const dados_consolidados = {
  ...input.payload_bms,
  ...input.dados_extraidos
};

// 🔹 status
const status = (input.campos_faltantes || []).length > 0
  ? 'incompleto'
  : 'completo';

return [
  {
    json: {
      dados_sadm,
      dados_manuais: {},
      dados_consolidados,
      campos_faltantes: input.campos_faltantes || [],
      status
    }
  }
];

