const supabaseData = items[0].json;
const novosDados = $('Edit Fields').first().json;

// =========================
// 🔹 HELPERS
// =========================
function isEmpty(value) {
  return (
    value === null ||
    value === undefined ||
    value === "" ||
    value === "00:00"
  );
}

function normalizeDate(date) {
  if (!date || date === "0") return null;
  return date;
}

// 🔥 parse string tipo: ["data_fim: 05-02-2026", "crm: 1234"]
function parseManualString(str) {
  if (!str) return {};

  try {
    const arr = JSON.parse(str);
    const result = {};

    arr.forEach(item => {
      const [key, value] = item.split(":").map(s => s.trim());
      if (!key || !value) return;

      if (key === "data_inicio" || key === "data_fim") {
        const [d, m, y] = value.split("-");
        result[key] = `${y}-${m}-${d}`;
      } else {
        result[key] = value;
      }
    });

    return result;
  } catch (e) {
    return {};
  }
}

// =========================
// 🔹 EXTRAÇÃO SADM NORMALIZADA
// =========================
const raw_sadm = supabaseData.dados_sadm || {};
const attendance = raw_sadm.attendance || {};
const doctor = raw_sadm.doctor || {};
const disease = raw_sadm.disease || {};
const attendance_info = raw_sadm.inputRaw?.attendance_information || {};

const dados_sadm = {
  data_inicio: normalizeDate(attendance.leave_start_date),
  data_fim: normalizeDate(attendance.leave_end_date),

  dias_consecutivos: attendance.leave_days ?? null,

  start_hours_certificates: attendance.leave_start_hour || null,
  end_hours_certificates: attendance.leave_end_hour || null,

  nome_medico: doctor.name || null,
  crm: doctor.crm_number || null,

  cid: disease.cid_code || null,

  periodo_indefinido: attendance_info.periodo_indefinido || "N",

  is_hours_certificates: attendance.leave_type === "hours",

  employee_id: supabaseData.dados_consolidados?.employee_id || novosDados.employee_id,
  phone: supabaseData.dados_consolidados?.phone || novosDados.phone,
  atestado_medico: novosDados.url_image || null
};

// =========================
// 🔹 DADOS MANUAIS
// =========================
const dados_manuais_antigos = supabaseData.dados_manuais || {};
const dados_parseados = parseManualString(novosDados.dados_manuais);

const dados_manuais = {
  ...dados_manuais_antigos,
  ...dados_parseados
};

// =========================
// 🔹 MERGE FINAL
// =========================
const final = {
  ...dados_sadm,
  ...dados_manuais
};

// =========================
// 🔹 NORMALIZAÇÃO FINAL
// =========================
final.data_inicio = normalizeDate(final.data_inicio);
final.data_fim = normalizeDate(final.data_fim);

// =========================
// 🔹 DETECÇÃO DE TIPO
// =========================
const periodoIndefinido = final.periodo_indefinido === "S";

let tipo_atestado = "dias";

if (periodoIndefinido) {
  tipo_atestado = "indefinido";
} else if (final.is_hours_certificates === true) {
  tipo_atestado = "horas";
}

// =========================
// 🔹 CAMPOS OBRIGATÓRIOS
// =========================
let obrigatorios = [
  "data_inicio",
  "nome_medico",
  "crm"
];

if (tipo_atestado === "horas") {
  obrigatorios.push(
    "start_hours_certificates",
    "end_hours_certificates"
  );
}

if (tipo_atestado === "dias") {
  obrigatorios.push(
    "dias_consecutivos",
    "data_fim"
  );
}

if (tipo_atestado === "indefinido") {
  obrigatorios.push("periodo_indefinido");
}

// =========================
// 🔹 CAMPOS FALTANTES
// =========================
const campos_faltantes = obrigatorios.filter(campo =>
  isEmpty(final[campo])
);

// =========================
// 🔹 STATUS
// =========================
const status =
  campos_faltantes.length === 0 ? "completo" : "incompleto";

// =========================
// 🔹 PAYLOAD BMS
// =========================
let payload_bms = {
  employee_id: final.employee_id,
  phone: final.phone,
  data_inicio: final.data_inicio,
  nome_medico: final.nome_medico,
  crm: final.crm,
  status_atestado: 1,
  cid: final.cid,
  atestado_medico: final.atestado_medico
};

if (tipo_atestado === "indefinido") {
  payload_bms = {
    ...payload_bms,
    periodo_indefinido: "S",
    dias_consecutivos: 0,
    is_hours_certificates: false
  };
}
else if (tipo_atestado === "dias") {
  payload_bms = {
    ...payload_bms,
    periodo_indefinido: "N",
    dias_consecutivos: final.dias_consecutivos,
    data_fim: final.data_fim,
    is_hours_certificates: false
  };
}
else {
  payload_bms = {
    ...payload_bms,
    is_hours_certificates: true,
    start_hours_certificates: final.start_hours_certificates,
    end_hours_certificates: final.end_hours_certificates
  };
}

// =========================
// 🔹 FORMATO PADRÃO (igual SADM)
// =========================
const dados_extraidos = {
  tipo_atestado,
  data_inicio: final.data_inicio,
  data_fim: final.data_fim,
  dias: final.dias_consecutivos,
  horas_inicio: final.start_hours_certificates,
  horas_fim: final.end_hours_certificates,
  nome_medico: final.nome_medico,
  crm: final.crm,
  cid: final.cid
};

// =========================
// 🔥 OUTPUT FINAL (COMPATÍVEL COM TUDO)
// =========================
return [
  {
    json: {
      status,
      tipo_atestado,
      campos_faltantes,

      dados_extraidos,

      dados_sadm,
      dados_manuais,
      dados_consolidados: final,

      payload_bms,

      // 🔥 ESSENCIAL PRA NÃO QUEBRAR NADA
      input_original: raw_sadm,
      origem_dados_externos: novosDados
    }
  }
];

// Este node NÃO confia no SADM como fonte completa.
// Ele aplica regras de consistência de negócio para garantir:
// - integridade dos dados
// - identificação correta de campos faltantes
// - preparação para coleta complementar via IA ou usuário

// =========================
// 🔹 REGRAS DE CAMPOS FALTANTES
// =========================
//
// Um campo é considerado faltante quando:
// - é null
// - é undefined
// - é string vazia ""
// - é "00:00" (caso de horários não preenchidos)
//
// =========================
// 🔹 REGRAS DE CAMPOS OBRIGATÓRIOS (BMS)
// =========================
//
// Existem 3 tipos de atestado:
//
// --------------------------------------------------
// 1. ATESTADO POR HORAS
// --------------------------------------------------
// Campos obrigatórios:
// - data_inicio
// - nome_medico
// - crm
// - is_hours_certificates = true
// - start_hours_certificates (horas_inicio)
// - end_hours_certificates (horas_fim)
//
// --------------------------------------------------
// 2. ATESTADO POR DIAS
// --------------------------------------------------
// Campos obrigatórios:
// - periodo_indefinido = "N"
// - dias_consecutivos (dias)
// - data_inicio
// - data_fim
// - nome_medico
// - crm
//
// --------------------------------------------------
// 3. ATESTADO INDEFINIDO
// --------------------------------------------------
// Campos obrigatórios:
// - periodo_indefinido = "S"
// - dias_consecutivos = 0
// - data_inicio
// - nome_medico
// - crm
//
// NÃO exige:
// - data_fim
// - horas
//
// --------------------------------------------------
// 🔹 REGRAS IMPORTANTES
// --------------------------------------------------
// - data_fim é obrigatória apenas para atestados por dias NÃO indefinidos
// - dias_consecutivos deve ser 0 quando periodo_indefinido = "S"
// - is_hours_certificates deve ser true apenas para atestados por horas
//
// --------------------------------------------------
// 🔹 NORMALIZAÇÃO
// --------------------------------------------------
// - datas inválidas como "0" são tratadas como null
// - horários "00:00" são considerados não preenchidos
//

const input = items[0].json;
const editFields = $('Edit Fields').item.json;

// =========================
// 🔹 HELPERS
// =========================
function normalizeDate(date) {
  if (!date || date === "0") return null;
  return date;
}

function isEmpty(value) {
  return (
    value === null ||
    value === undefined ||
    value === "" ||
    value === "00:00"
  );
}

// =========================
// 🔹 DETECÇÃO PERÍODO INDEFINIDO
// =========================
const periodoIndefinidoFlag =
  input?.inputRaw?.attendance_information?.periodo_indefinido === "S";

// =========================
// 🔹 EXTRAÇÃO DOS DADOS
// =========================
const attendance = input.attendance || {};
const doctor = input.doctor || {};
const disease = input.disease || {};

// =========================
// 🔹 NORMALIZAÇÃO
// =========================
const dados = {
  tipo_atestado: periodoIndefinidoFlag
    ? "indefinido"
    : attendance.leave_type === "hours"
    ? "horas"
    : "dias",

  data_inicio: normalizeDate(attendance.leave_start_date),
  data_fim: normalizeDate(attendance.leave_end_date),

  dias: periodoIndefinidoFlag ? 0 : attendance.leave_days ?? null,

  horas_inicio: attendance.leave_start_hour || null,
  horas_fim: attendance.leave_end_hour || null,

  nome_medico: doctor.name || null,
  crm: doctor.crm_number || null,

  cid: disease.cid_code || null,
};

// =========================
// 🔹 FLAGS DE TIPO
// =========================
const isHoras = dados.tipo_atestado === "horas";
const isDias = dados.tipo_atestado === "dias";
const isIndefinido = dados.tipo_atestado === "indefinido";

// =========================
// 🚨 VALIDAÇÃO DE CONSISTÊNCIA (máquina de estados)
// =========================
if (isIndefinido && isHoras) {
  throw new Error("Estado inválido: atestado indefinido não pode ser por horas");
}

// =========================
// 🔹 CAMPOS OBRIGATÓRIOS (BMS-ALIGNED)
// =========================
let campos_obrigatorios = [
  "data_inicio",
  "nome_medico",
  "crm"
];

if (isHoras) {
  campos_obrigatorios.push("horas_inicio", "horas_fim");
}

if (isDias) {
  campos_obrigatorios.push("dias", "data_fim");
}

// indefinido → já tratado (dias = 0)

// =========================
// 🔹 CAMPOS FALTANTES
// =========================
const campos_faltantes = campos_obrigatorios.filter(campo => {
  return isEmpty(dados[campo]);
});

// =========================
// 🔹 STATUS
// =========================
const status = campos_faltantes.length === 0 ? "completo" : "incompleto";

// =========================
// 🔹 PAYLOAD BMS
// =========================
let payload_bms = {
  employee_id: editFields.employee_id,
  phone: editFields.phone,
  data_inicio: dados.data_inicio,
  nome_medico: dados.nome_medico,
  crm: dados.crm,
  status_atestado: 1,
  cid: dados.cid,
  atestado_medico: editFields.midia_url
};

// =========================
// 🔹 REGRAS POR TIPO (BMS)
// =========================
if (isIndefinido) {
  payload_bms = {
    ...payload_bms,
    periodo_indefinido: "S",
    dias_consecutivos: 0,
    is_hours_certificates: false
  };
}

if (isDias) {
  payload_bms = {
    ...payload_bms,
    periodo_indefinido: "N",
    dias_consecutivos: dados.dias,
    data_fim: dados.data_fim,
    is_hours_certificates: false
  };
}

if (isHoras) {
  payload_bms = {
    ...payload_bms,
    periodo_indefinido: "N",
    is_hours_certificates: true,
    start_hours_certificates: dados.horas_inicio,
    end_hours_certificates: dados.horas_fim
  };
}

// =========================
// 🔹 OUTPUT
// =========================
return [
  {
    json: {
      status,
      tipo_atestado: dados.tipo_atestado,
      campos_faltantes,
      dados_extraidos: dados,
      payload_bms,
      input_original: input,
      origem_dados_externos: editFields
    }
  }
];

// Recupera o item de entrada do nó específico
const input = $('Edit Fields').first().json;
const url = input.url_image;

if (!url) {
  return [{ json: { error: "URL não fornecida" } }];
}

// --------------------------------------------------
// Gera FILE_PREFIX único (timestamp + id se existir)
// --------------------------------------------------

const now = new Date();
const pad = (n, size) => String(n).padStart(size, "0");

const timestamp =
  now.getFullYear() +
  pad(now.getMonth() + 1, 2) +
  pad(now.getDate(), 2) +
  pad(now.getHours(), 2) +
  pad(now.getMinutes(), 2) +
  pad(now.getSeconds(), 2) +
  pad(now.getMilliseconds(), 3);

const id = input.id || "noid";
const FILE_PREFIX = `${timestamp}_${id}`;

// --------------------------------------------------
// Detecta extensão do arquivo
// --------------------------------------------------

const cleanUrl = url.split('?')[0].toLowerCase();

let extension = "unknown";

if (cleanUrl.includes(".pdf")) {
  extension = "pdf";
} else if (
  cleanUrl.includes(".jpg") ||
  cleanUrl.includes(".jpeg") ||
  cleanUrl.includes(".png") ||
  cleanUrl.includes(".webp") ||
  cleanUrl.includes(".bmp")
) {
  extension = "img";
}

let result = {};

if (extension === "img") {
  result = {
    extension: "img",
    url_final: url
  };
} else if (extension === 'pdf') {
  result = {
    extension: "pdf",
    url_final: url
  };
} else {
  result = {
    extension: "unknown",
    url_final: url
  };
}

// --------------------------------------------------
// Retorno FINAL
// --------------------------------------------------

return [
  {
    json: {
      ...result,
      FILE_PREFIX,
      url_image: url, // ← GARANTE que está vindo do nó Verifica input da API
      source_node: "Verifica input da API" // opcional para debug
    }
  }
];

// Captura os dados do item atual que chegou ao nó
const currentItem = $input.first().json;

let urlFinal = null;

try {
  // 1. Tenta buscar do caminho do PDF (Upload a file1)
  // Usamos o optional chaining (?.) para não travar se o nó não existir
  const uploadNode = $("API PDF Converter")?.item?.json;
  if (uploadNode && uploadNode.conversionUrl) {
    urlFinal = uploadNode.conversionUrl;
  }
} catch (e) {
  // Nó não executado, apenas ignora o erro
}

if (!urlFinal) {
  try {
    // 2. Tenta buscar do caminho da Imagem (Switch / identifica a extensao)
    const switchNode = $("Switch")?.item?.json;
    if (switchNode && switchNode.url_final) {
      urlFinal = switchNode.url_final;
    }
  } catch (e) {
    // Nó não executado, apenas ignora
  }
}

// Retorna um único objeto com a URL consolidada
return {
  url_consolidada: urlFinal,
  ...currentItem
};

